import { useState } from "react";
import { X, Star, UploadCloud } from "lucide-react";
import '../index.css'
import { useCreateReview } from "../Hooks/review";

export const AddReview = ({ setAddReview, productId }: { setAddReview: (addReview: boolean) => void, productId: string }) => {


    const { mutateAsync: createReview, isPending: isLoadingReview } = useCreateReview();

    const [reviewData, setReviewData] = useState({
        rating: 0,
        hoverRating: 0,
        title: "",
        comment: "",
        images: [] as File[],
        recommended: false
    });

    const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
            setReviewData((prev) => ({ ...prev, images: Array.from(e.target.files) }));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        const formData = new FormData();
        formData.append("productId", productId);
        formData.append("rating", reviewData.rating.toString());
        formData.append("title", reviewData.title);
        formData.append("comment", reviewData.comment);
        formData.append("recommended", reviewData.recommended.toString());

        if (reviewData.images && reviewData.images.length > 0) {
            reviewData.images.forEach((img) => {
                formData.append("images", img);
            });
        }

        try {
            await createReview(formData as any);
            setReviewData({
                rating: 0,
                hoverRating: 0,
                title: "",
                comment: "",
                images: [],
                recommended: false,
            });
            setAddReview(false);
        } catch (error) {
            console.error(error);
        }
    };

    return (
        <div className="fixed inset-0 z-1000 flex items-center justify-center p-4 backdrop-blur-md bg-black/40 transition-opacity animate-in fade-in duration-200">
            <div className="animate-fade-in-up-delay-1 bg-white rounded-2xl sm:rounded-3xl shadow-2xl border border-gray-100 p-4 sm:p-6 md:p-8 w-full max-w-lg relative animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto no-scrollbar">

                {isLoadingReview && (
                    <div className="absolute top-0 bottom-0 h-full z-50 left-0 right-0 flex items-center justify-center bg-white/50 rounded-2xl sm:rounded-3xl">
                        <div className="dot-spinner">
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                        </div>
                    </div>
                )}

                <div className="sticky -top-4 sm:-top-6 md:-top-8 bg-white py-3 sm:py-4 z-40 border-b border-gray-100 flex items-center justify-between mb-4 sm:mb-6">
                    <div>
                        <h2 className="text-base sm:text-lg font-bold text-gray-900 tracking-tight">Write a Review</h2>
                        <p className="text-[10px] sm:text-xs text-gray-500 mt-0.5 sm:mt-1">Share your experience with this product.</p>
                    </div>
                    <button
                        onClick={() => setAddReview(false)}
                        className="p-1.5 sm:p-2 hover:bg-gray-100 rounded-full transition-colors"
                    >
                        <X className="w-5 h-5 sm:w-6 sm:h-6 text-gray-500 hover:text-gray-900" />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4 sm:space-y-6">

                    <div>
                        <label className="block text-xs sm:text-sm font-semibold text-gray-900 mb-1.5 sm:mb-2">Overall Rating *</label>
                        <div className="flex gap-1">
                            {[1, 2, 3, 4, 5].map((star) => (
                                <Star
                                    key={star}
                                    className={`w-6 h-6 sm:w-7 sm:h-7 cursor-pointer transition-all duration-200 ${(reviewData.hoverRating || reviewData.rating) >= star
                                        ? "fill-yellow-400 text-yellow-400 scale-110"
                                        : "fill-gray-100 text-gray-300 hover:scale-110"
                                        }`}
                                    onClick={() => setReviewData((prev) => ({ ...prev, rating: star }))}
                                    onMouseEnter={() => setReviewData((prev) => ({ ...prev, hoverRating: star }))}
                                    onMouseLeave={() => setReviewData((prev) => ({ ...prev, hoverRating: 0 }))}
                                />
                            ))}
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs sm:text-sm font-semibold text-gray-900 mb-1.5 sm:mb-2">Review Title *</label>
                        <input
                            type="text"
                            placeholder="Sum up your experience in a few words"
                            name="title"
                            value={reviewData.title}
                            onChange={(e) => setReviewData((prev) => ({ ...prev, title: e.target.value }))}
                            className="w-full px-3 py-2 sm:px-4 sm:py-2.5 rounded-lg sm:rounded-xl text-xs sm:text-sm border border-gray-200 bg-gray-50 focus:bg-white focus:ring-2 focus:ring-gray-900 focus:border-transparent outline-none transition-all placeholder:text-gray-400"
                        />
                    </div>

                    <div>
                        <label className="block text-xs sm:text-sm font-semibold text-gray-900 mb-1.5 sm:mb-2">Detailed Review *</label>
                        <textarea
                            rows={4}
                            placeholder="Share your thoughts (optional)"
                            name="comment"
                            value={reviewData.comment}
                            onChange={(e) => setReviewData((prev) => ({ ...prev, comment: e.target.value }))}
                            className="w-full px-3 py-2 sm:px-4 sm:py-2.5 rounded-lg sm:rounded-xl text-xs sm:text-sm border border-gray-200 bg-gray-50 focus:bg-white focus:ring-2 focus:ring-gray-900 focus:border-transparent outline-none transition-all placeholder:text-gray-400 resize-none"
                            required
                        ></textarea>
                    </div>

                    <div>
                        <label className="block text-xs sm:text-sm font-semibold text-gray-900 mb-1.5 sm:mb-2">Do you recommend this product? *</label>
                        <div className="flex items-center gap-4">
                            <label className="flex items-center gap-1.5 sm:gap-2 cursor-pointer">
                                <input
                                    type="radio"
                                    name="recommended"
                                    value="true"
                                    checked={reviewData.recommended === true}
                                    onChange={(e) => setReviewData((prev) => ({ ...prev, recommended: e.target.value === "true" }))}
                                    className="w-3.5 h-3.5 sm:w-4 sm:h-4"
                                    required
                                />
                                <span className="text-xs sm:text-sm text-gray-700">Yes</span>
                            </label>
                            <label className="flex items-center gap-1.5 sm:gap-2 cursor-pointer">
                                <input
                                    type="radio"
                                    name="recommended"
                                    value="false"
                                    checked={reviewData.recommended === false}
                                    onChange={(e) => setReviewData((prev) => ({ ...prev, recommended: e.target.value === "true" }))}
                                    className="w-3.5 h-3.5 sm:w-4 sm:h-4"
                                    required
                                />
                                <span className="text-xs sm:text-sm text-gray-700">No</span>
                            </label>
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs sm:text-sm font-semibold text-gray-900 mb-1.5 sm:mb-2">
                            Add Photos (Optional)
                        </label>

                        <label
                            htmlFor="file-upload"
                            className="flex flex-col items-center justify-center px-4 py-6 sm:px-6 sm:py-8 border-2 border-dashed border-gray-300 rounded-lg sm:rounded-xl cursor-pointer hover:border-black hover:bg-gray-50 transition-all"
                        >
                            <UploadCloud className="w-8 h-8 sm:w-12 sm:h-12 text-gray-400 mb-2 sm:mb-3" />

                            <p className="text-xs sm:text-sm font-medium text-gray-700">
                                Click to upload images
                            </p>

                            <p className="text-[10px] sm:text-xs text-gray-500 mt-1">
                                PNG, JPG, WEBP up to 10MB
                            </p>

                            <input
                                id="file-upload"
                                type="file"
                                multiple
                                accept="image/*"
                                onChange={handleImageChange}
                                className="hidden"
                            />

                            {reviewData.images.length > 0 && (
                                <div className="flex flex-wrap gap-2 sm:gap-3 mt-3 sm:mt-4">
                                    {reviewData.images.map((img, index) => (
                                        <div
                                            key={index}
                                            className="relative group w-16 h-16 sm:w-20 sm:h-20 rounded-lg overflow-hidden border border-gray-200 shadow-sm"
                                        >
                                            <img
                                                src={URL.createObjectURL(img)}
                                                alt={`preview-${index}`}
                                                className="w-full h-full object-cover"
                                            />
                                            <button
                                                type="button"
                                                onClick={(e) => {
                                                    e.preventDefault();
                                                    setReviewData((prev) => ({
                                                        ...prev,
                                                        images: prev.images.filter((_, i) => i !== index)
                                                    }))
                                                }}
                                                className="absolute top-1 right-1 p-0.5 sm:p-1 cursor-pointer bg-white/80 hover:bg-red-400 rounded-full sm:opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center shadow-sm"
                                            >
                                                <X className="w-3 h-3 sm:w-3.5 sm:h-3.5 text-gray-900 sm:text-gray-100" />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </label>
                    </div>

                    <div className="flex gap-2.5 sm:gap-3 pt-2">
                        <button
                            type="button"
                            onClick={() => setAddReview(false)}
                            className="flex-1 px-4 py-2.5 sm:px-6 sm:py-3.5 text-xs sm:text-sm font-bold text-gray-700 bg-white border-2 border-gray-200 rounded-lg sm:rounded-xl hover:bg-gray-50 transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            className="flex-1 px-4 py-2.5 sm:px-6 sm:py-3.5 text-xs sm:text-sm font-bold text-white bg-gray-900 rounded-lg sm:rounded-xl hover:bg-gray-800 transition-colors disabled:opacity-50"
                            disabled={!reviewData.rating || !reviewData.title || !reviewData.comment}
                        >
                            Submit Review
                        </button>
                    </div>
                </form>
            </div>
        </div>
    )
}

import { useEffect, useState } from "react";
import { FaArrowRight, FaRegStar, FaStar, FaStarHalfAlt } from "react-icons/fa";
import { useNavigate } from "react-router";
import type { Product } from "../Api/productApi";
import { useAddToCart } from "../Hooks/cart";
import { FaRegHeart } from "react-icons/fa6";
import { FaHeart } from "react-icons/fa6";
import '../index.css'
import { useAddToWishList, useRemoveFromWishList, useGetWishList } from "../Hooks/wishList";
import { toast } from "sonner";
import ReactGA from "react-ga4";
import { useGetProductAllReview } from "../Hooks/review";

export const Detail = ({
    curruntProduct,
    showDetail,
    setShowDetail,
}: {
    curruntProduct: Product;
    showDetail: boolean;
    setShowDetail: (v: boolean) => void;
}) => {

    const { mutateAsync: addToCart, isPending: cartPending } = useAddToCart();
    const { mutateAsync: addToWishList, isPending: wishListPending } = useAddToWishList();
    const { mutateAsync: removeFromWishList, isPending: removeFromWishListPending } = useRemoveFromWishList();
    const { data: wishListData } = useGetWishList();
    const { data: productReviews } = useGetProductAllReview(curruntProduct?._id);
    const isPending = cartPending || wishListPending || removeFromWishListPending;

    const navigate = useNavigate();
    const [count, setCount] = useState<number>(1);
    const [selectedSize, setSelectedSize] = useState<string>("");
    const [selectedColor, setSelectedColor] = useState<string>("");
    const [activeImage, setActiveImage] = useState<number>(0);
    const [added, setAdded] = useState<boolean>(false);

    useEffect(() => {
        ReactGA.event({
            category: "Product",
            action: "View Product",
            label: curruntProduct?.title,
        });
    }, [curruntProduct]);


    useEffect(() => {
        if (showDetail) {
            document.body.style.overflow = "hidden";
        }
        return () => {
            document.body.style.overflow = "";
        };
    }, [showDetail]);

    const handleAdd = async () => {

        if (!selectedColor) {
            toast.error("Please select color", {
                duration: 1500
            });
            return;
        }

        if (!selectedSize) {
            toast.error("Please select size", {
                duration: 1500
            });
            return;
        }

        if (curruntProduct?.variants?.some((v: { size: string, stock: number }) => v.size === selectedSize && v.stock === 0)) {
            toast.error("Selected size is out of stock", {
                duration: 1500
            });
            return;
        }

        ReactGA.event({
            category: "Cart",
            action: "Add To Cart",
            label: curruntProduct.title,
        });

        const data = await addToCart({ productId: curruntProduct?._id, quantity: count, size: selectedSize, color: selectedColor })

        if (data) {
            setAdded(true);
            setTimeout(() => setAdded(false), 2000);
            setShowDetail(false)
        }
    };

    const moreDetails = (product: Product) => {
        navigate("/more-details", { replace: true, state: { product } })
    }

    const inStock = curruntProduct?.variants.reduce((acc, variant) => acc + variant.stock, 0) > 0;
    const isWishlisted = wishListData?.data?.wishlist?.some((item: any) => item.productId === curruntProduct?._id);
    const totalRating = productReviews?.reduce((acc, review) => acc + review.rating, 0);
    const averageRating = totalRating / productReviews?.length;

    const StarRating = ({ rating = 0 }) => {
        return (
            <div className="flex gap-1 text-yellow-400 text-sm">
                {[1, 2, 3, 4, 5].map((star) => {
                    if (rating >= star) {
                        return <FaStar key={star} />;
                    }
                    if (rating >= star - 0.5) {
                        return <FaStarHalfAlt key={star} />;
                    }
                    return <FaRegStar key={star} />;
                })}
            </div>
        );
    };

    return (
        <div
            className={`fixed inset-0 z-10000 flex items-center justify-center transition-all duration-500 ${showDetail ? "opacity-100 pointer-events-auto" : "opacity-0 pointer-events-none"
                }`}
        >

            <div
                className="absolute inset-0 bg-black/60 backdrop-blur-sm"
                onClick={() => setShowDetail(false)}
            />

            <div
                className={`relative w-[92%] max-w-5xl h-[88vh] bg-white rounded-3xl overflow-hidden shadow-[0_32px_80px_rgba(0,0,0,0.25)] flex flex-col md:flex-row transition-all duration-500 ${showDetail ? "scale-100 translate-y-0" : "scale-95 translate-y-6"
                    }`}
            >

                {isPending && (
                    <div className="absolute top-0 bottom-0 h-full z-50 left-0 right-0 flex items-center justify-center bg-black/30">
                        <div className="dot-spinner">
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                            <div className="dot-spinner__dot"></div>
                        </div>
                    </div>
                )}

                <button
                    onClick={() => setShowDetail(false)}
                    className="absolute top-3 right-3 z-10000 w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-white/90 backdrop-blur-md border border-gray-200 flex items-center justify-center text-gray-600 hover:bg-gray-100 hover:text-gray-900 transition-all duration-200 cursor-pointer shadow-sm"
                >
                    <svg className="w-4 h-4 sm:w-5 sm:h-5" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                </button>

                <div className="w-full md:w-[55%] h-[45vh] md:h-full bg-gray-50 relative flex flex-col shrink-0">

                    <div className="flex-1 relative overflow-hidden">
                        <img
                            src={curruntProduct?.images[activeImage] || curruntProduct?.images[0]}
                            className="w-full h-full object-cover transition-all duration-500"
                            alt="Product"
                        />

                        <div className="absolute top-4 left-4 sm:top-5 sm:left-5 flex flex-col gap-2">
                            <span className="bg-gray-900 text-white text-[8px] sm:text-[9px] font-bold uppercase tracking-widest px-2 py-1 sm:px-3 sm:py-1.5 rounded-md">
                                Bestseller
                            </span>
                            <span className="bg-emerald-500 text-white text-[8px] sm:text-[9px] font-bold uppercase tracking-widest px-2 py-1 sm:px-3 sm:py-1.5 rounded-md">
                                {curruntProduct?.discountPrice === 0 ? "New Arrival" : `${Math.floor(((curruntProduct?.basePrice - curruntProduct?.discountPrice) / curruntProduct?.basePrice) * 100)}% Off`}
                            </span>
                        </div>
                    </div>


                    <div className="flex justify-between items-center gap-2 p-2 sm:p-3 bg-white border-t border-gray-100">
                        <div className="flex gap-1.5 overflow-x-auto no-scrollbar">
                            {curruntProduct?.images?.map((img, i) => (
                                <button
                                    key={i}
                                    onClick={() => setActiveImage(i)}
                                    className={`w-12 h-12 sm:w-16 sm:h-16 rounded-xl overflow-hidden border-2 transition-all duration-200 cursor-pointer shrink-0 ${activeImage === i
                                        ? "border-gray-900 shadow-md"
                                        : "border-transparent opacity-60 hover:opacity-100"
                                        }`}
                                >
                                    <img src={img} className="w-full h-full object-cover" alt={`View ${i + 1}`} />
                                </button>
                            ))}

                        </div>
                        <div className="pl-1 sm:pl-2 shrink-0">
                            <button
                                className={`py-2 sm:py-3.5 rounded-2xl font-semibold text-xs sm:text-sm md:text-md tracking-wider transition-all duration-300 cursor-pointer text-gray-600 hover:text-gray-900 hover:underline hover:underline-offset-4`}
                                onClick={() => moreDetails(curruntProduct)}
                            >
                                <p className="flex justify-center items-center gap-1.5 sm:gap-3 transition-all duration-300">
                                    <span className="hidden sm:inline">Show More Details</span>
                                    <span className="sm:hidden">More Details</span>
                                    <FaArrowRight className="w-3 h-3 sm:w-4 sm:h-4" />
                                </p>
                            </button>
                        </div>
                    </div>
                </div>


                <div className="w-full md:w-[45%] flex flex-col flex-1 md:h-full overflow-hidden">
                    <div className="flex-1 overflow-y-auto px-4 py-6 sm:px-6 sm:py-8 md:px-8 space-y-5 sm:space-y-6">

                        <span className="text-[8px] sm:text-[9px] text-gray-400 font-medium uppercase tracking-widest">Streetwear</span>
                        <span className="text-[8px] sm:text-[9px] text-gray-400 font-medium uppercase tracking-widest"> - </span>
                        <span className="text-[8px] sm:text-[9px] text-gray-400 font-medium uppercase tracking-widest">{curruntProduct?.title}</span>


                        <div>
                            <h2 className="text-xl sm:text-2xl font-extrabold text-gray-900 tracking-tight leading-tight">
                                {curruntProduct?.seoTitle}
                            </h2>
                            <p className="mt-0.5 sm:mt-1 text-[10px] sm:text-[12px] text-gray-400 font-medium break-all">@{curruntProduct?.slug}</p>
                        </div>


                        <div className="flex items-center gap-2 sm:gap-3">
                            <span className="text-xs font-semibold text-gray-500">
                                <StarRating rating={averageRating} />
                            </span>
                            <span className="text-[10px] sm:text-[11px] text-[#aaa]">{averageRating ? averageRating.toFixed(1) : ""}</span>
                        </div>


                        <div className="flex items-baseline gap-2 sm:gap-3 flex-wrap">
                            <span className="text-2xl sm:text-3xl font-extrabold text-gray-900">Γé╣{curruntProduct?.discountPrice ? curruntProduct?.discountPrice : curruntProduct?.basePrice}</span>
                            {curruntProduct?.discountPrice !== 0 && (
                                <span className="text-base sm:text-lg text-gray-400 line-through font-medium">Γé╣{curruntProduct?.basePrice}</span>
                            )}
                            {curruntProduct?.discountPrice !== 0 && (
                                <span className="bg-emerald-50 text-emerald-600 text-[10px] sm:text-xs font-bold px-2 py-0.5 sm:px-2.5 sm:py-1 rounded-full whitespace-nowrap">
                                    Save {`Γé╣${curruntProduct?.basePrice - curruntProduct?.discountPrice}`}
                                </span>
                            )}
                        </div>

                        <p className="text-xs sm:text-sm text-gray-500 leading-relaxed">
                            {curruntProduct?.description}
                        </p>


                        <div className="h-px bg-gray-100" />


                        <div>
                            <div className="flex items-center justify-between mb-2 sm:mb-3">
                                <p className="text-[10px] sm:text-xs font-bold text-gray-800 uppercase tracking-wider">Color</p>
                                <p className="text-[10px] sm:text-xs text-gray-400 font-medium">{selectedColor}</p>
                            </div>
                            <div className="flex gap-3">
                                {!selectedSize && (
                                    <>
                                        {[...new Set(curruntProduct?.variants.map((v) => v.color))].map((color) => (
                                            <button
                                                key={color}
                                                onClick={() => setSelectedColor(color)}
                                                title={color}
                                                className={`w-6 h-6 sm:w-8 sm:h-8 md:w-9 md:h-9 rounded-full transition-all duration-200 cursor-pointer relative ${selectedColor === color
                                                    ? "ring-2 ring-offset-2 ring-gray-900 scale-110"
                                                    : "hover:scale-105 ring-1 ring-gray-200"
                                                    }`}
                                                style={{ backgroundColor: color }}
                                            >
                                                {selectedColor === color && (
                                                    <svg className="absolute inset-0 m-auto w-4 h-4" fill="none" stroke={['white', '#ffffff', '#fff'].includes(color.toLowerCase()) ? '#111' : '#fff'} strokeWidth="3" viewBox="0 0 24 24">
                                                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                                                    </svg>
                                                )}
                                            </button>
                                        ))}
                                    </>
                                )}

                                {selectedSize && (
                                    <>
                                        {[...new Set(curruntProduct?.variants.filter((v: any) => v.size === selectedSize && v.stock > 0).map((v: any) => v.color))].map((color: any) => (
                                            <button
                                                key={color}
                                                onClick={() => setSelectedColor(color)}
                                                title={color}
                                                className={`w-6 h-6 sm:w-8 sm:h-8 md:w-9 md:h-9 rounded-full transition-all duration-200 cursor-pointer relative ${selectedColor === color
                                                    ? "ring-2 ring-offset-2 ring-gray-900 scale-110"
                                                    : "hover:scale-105 ring-1 ring-gray-200"
                                                    }`}
                                                style={{ backgroundColor: color }}
                                            >
                                                {selectedColor === color && (
                                                    <svg className="absolute inset-0 m-auto w-4 h-4" fill="none" stroke={['white', '#ffffff', '#fff'].includes(color.toLowerCase()) ? '#111' : '#fff'} strokeWidth="3" viewBox="0 0 24 24">
                                                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                                                    </svg>
                                                )}
                                            </button>
                                        ))}
                                    </>
                                )}

                            </div>
                        </div>


                        <div>
                            <div className="flex items-center justify-between mb-2 sm:mb-3">
                                <p className="text-[10px] sm:text-xs font-bold text-gray-800 uppercase tracking-wider">Size</p>
                                <button className="text-[10px] sm:text-xs text-gray-400 underline underline-offset-2 sm:underline-offset-3 hover:text-gray-600 transition-colors cursor-pointer">
                                    Size Guide
                                </button>
                            </div>

                            {!selectedColor && (
                                <div className="flex gap-2 flex-wrap">
                                    {[... new Set(curruntProduct?.variants.map((v: { size: string }) => v.size))].map((s: string) => (
                                        <button
                                            key={s}
                                            onClick={() => setSelectedSize(s)}
                                            className={`h-6 sm:h-8 md:h-9 px-2 sm:px-3 rounded-lg sm:rounded-xl text-[8px] sm:text-[10px] md:text-[11px] font-bold uppercase tracking-wider transition-all duration-200 cursor-pointer ${selectedSize === s
                                                ? "bg-gray-900 text-white shadow-md shadow-gray-900/20"
