import { useEffect, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { toast } from "sonner";
import { LeftBar } from './Leftbar';
import { Login as LoginHook } from '../Hooks/Auth';
import { getCart } from '../Api/cartApi';
import { useDispatch, useSelector } from 'react-redux';
import { setUser } from '../Redux/authSlice';
import type { RootState } from '../Redux/store';
import { setCart } from '../Redux/cartSlice';
import { GoogleLogin } from "@react-oauth/google";
import { useGoogleLogin } from '../Hooks/user';
import '../index.css'

export const Login = () => {

    const dispatch = useDispatch();
    const token = useSelector((state: RootState) => state.auth.token);
    const { mutateAsync: login, isPending } = LoginHook();
    const { mutateAsync: googleLogin } = useGoogleLogin();

    const navigate = useNavigate();
    const [showPassword, setShowPassword] = useState<boolean>(false);

    const showPasswordHandler = () => {
        setShowPassword(!showPassword);
    }

    const [data, setData] = useState({
        email: "",
        password: ""
    });

    const HandleInput = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setData({
            ...data,
            [name]: value
        });
    }

    const HandleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();

        if (!data.email) {
            toast.error("Email is required", {
                duration: 1500,
            });
            return;
        }

        if (!data.password) {
            toast.error("Password is required", {
                duration: 1500,
            });
            return;
        }

        if (data.password.length < 6) {
            toast.error("Password must be at least 6 characters", {
                duration: 1500,
            });
            return;
        }

        if (!/\d/.test(data.password)) {
            toast.error("Password must contain at least one number", {
                duration: 1500,
            });
            return;
        }

        if (!/[@$!%*?&]/.test(data.password)) {
            toast.error("Password must contain at least one special character", {
                duration: 1500,
            });
            return;
        }

        if (!/[A-Z]/.test(data.password)) {
            toast.error("Password must contain at least one uppercase letter", {
                duration: 1500,
            });
            return;
        }

        if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) {
            toast.error("Invalid email format", {
                duration: 1500,
            });
            return;
        }

        try {
            const result = await login(data);

            if (result.success === false) {
                toast.error("Something Issuse In Frontend", {
                    duration: 1500,
                });
                return;
            }

            toast.success(result.message, {
                duration: 1500,
            });

            dispatch(
                setUser({
                    token: result.data.token,
                    user: {
                        name: result.data.user.name,
                        email: result.data.user.email
                    },
                    activeNav: ''
                })
            )

            try {
                const fetchedCart = await getCart();

                if (fetchedCart && fetchedCart.length > 0) {
                    dispatch(setCart(fetchedCart));
                }
            } catch (cartError) {
                console.error("Failed to fetch cart after login:", cartError);
            }

            setTimeout(() => {
                navigate("/");
            }, 1500);

        } catch (error) {
            const err = error as { response?: { data?: { message?: string } } };
            const msg = err.response?.data?.message || "Login failed. Please try again.";
            toast.error(msg, {
                duration: 1500,
            });
        }
    };

    useEffect(() => {
        if (token) {
            toast.success("User already logged in", {
                duration: 1500,
            });
            setTimeout(() => {
                navigate("/");
            }, 1500);
        }
    }, [dispatch, navigate]);

    const handleGoogleLogin = async (response: any) => {
        try {
            const res = await googleLogin(response.credential);
            if (res.success) {

                dispatch(
                    setUser({
                        token: res.data.token,
                        user: {
                            name: res.data.user.name,
                            email: res.data.user.email
                        },
                        activeNav: ''
                    })
                )

                try {
                    const fetchedCart = await getCart();

                    if (fetchedCart && fetchedCart.length > 0) {
                        dispatch(setCart(fetchedCart));
                    }
                } catch (cartError) {
                    console.error("Failed to fetch cart after login:", cartError);
                }

                setTimeout(() => {
                    navigate("/");
                }, 1500);
            }
        } catch (error) {
            const err = error as { response?: { data?: { message?: string } } };
            const msg = err.response?.data?.message || "Login failed. Please try again.";
            toast.error(msg, {
                duration: 1500,
            });
        }
    }

    return (
        <>
            <div className="min-h-screen bg-white flex">

                <LeftBar />

                <div className="w-full lg:w-1/2 flex items-center justify-center p-4 sm:p-8 md:p-12">
                    <div className="relative w-full max-w-sm space-y-6 sm:space-y-8">

                        {isPending && (
                            <div className="absolute top-0 bottom-0 h-full z-50 left-0 right-0 flex items-center justify-center bg-white/50">
                                <div className="dot-spinner">
                                    <div className="dot-spinner__dot"></div>
                                    <div className="dot-spinner__dot"></div>
                                    <div className="dot-spinner__dot"></div>
                                    <div className="dot-spinner__dot"></div>
                                    <div className="dot-spinner__dot"></div>
                                    <div className="dot-spinner__dot"></div>
                                    <div className="dot-spinner__dot"></div>
                                    <div className="dot-spinner__dot"></div>
                                </div>
                            </div>
                        )}
                        <div>
                            <h1 className="text-xl sm:text-2xl font-bold text-zinc-800 tracking-tight">Login</h1>
                            <p className="text-xs sm:text-sm text-zinc-400 mt-1">Welcome back. Enter your credentials to access your account.</p>
                        </div>

                        <GoogleLogin onSuccess={handleGoogleLogin} onError={() => { toast.error("Google Login failed"); }} />

                        <div className="flex items-center gap-3">
                            <div className="flex-1 h-px bg-zinc-200" />
                            <span className="text-xs text-zinc-400 font-medium">or</span>
                            <div className="flex-1 h-px bg-zinc-200" />
                        </div>

                        <form className="space-y-3 sm:space-y-4" onSubmit={HandleSubmit}>

                            <input
                                type="email"
                                placeholder="Email"
                                className="w-full rounded-xl bg-zinc-100 border border-transparent focus:bg-white focus:border-zinc-300 px-3 py-2 sm:px-4 sm:py-2.5 text-xs sm:text-sm text-zinc-800 placeholder-zinc-400 transition outline-none"
                                name="email"
                                value={data.email}
                                onChange={HandleInput}
                            />

                            <div className='relative'>
                                <input
                                    type={showPassword ? "text" : "password"}
                                    placeholder="Password"
                                    className="w-full rounded-xl bg-zinc-100 border border-transparent focus:bg-white focus:border-zinc-300 px-3 py-2 sm:px-4 sm:py-2.5 text-xs sm:text-sm text-zinc-800 placeholder-zinc-400 transition outline-none"
                                    name="password"
                                    value={data.password}
                                    onChange={HandleInput}
                                />
                                <button type="button" onClick={showPasswordHandler} className='absolute top-2 sm:top-2.5 right-3 text-zinc-400 hover:text-zinc-600 focus:outline-none transition text-sm sm:text-base'>
                                    {showPassword ? "≡ƒÖê" : "≡ƒæü∩╕Å"}
                                </button>
                            </div>

                            <button type="submit" className="w-full rounded-xl bg-zinc-800 hover:bg-zinc-900 text-white font-bold py-2 sm:py-2.5 text-xs sm:text-sm transition-all duration-300 shadow-md cursor-pointer">
                                Login
                            </button>
                        </form>

                        <p className="text-center text-xs text-zinc-500">
                            Don't have an account?{" "}
                            <Link to="/signup"
                                className="text-zinc-800 font-bold hover:underline cursor-pointer"
                            >
                                Sign Up
                            </Link>
                        </p>

                    </div>
                </div>
            </div>
        </>

    )
}

import { useEffect, useState } from "react"
import { Reviews } from "./Review";
import { useLocation } from "react-router-dom";
import type { Product } from "../Api/productApi";
import { useAddToCart } from "../Hooks/cart";
import { useAddToWishList, useGetWishList, useRemoveFromWishList } from "../Hooks/wishList";
import { FaHeart, FaRegHeart, FaRegStar, FaStar, FaStarHalfAlt } from "react-icons/fa";
import '../index.css'
import { SizeGuide } from "./SizeGuide";
import { RecommendProduct } from "./RecommendProduct";
import ReactGA from "react-ga4";
import { QA } from "./QA";
import { useGetProductAllReview } from "../Hooks/review";

interface LocationState {
    product: Product;
}

export const MoreDetails = () => {

    const location = useLocation();
    const { product } = location.state as LocationState;

    useEffect(() => {
        window.scrollTo({ top: 0, behavior: "smooth" });
    }, [product?._id]);

    useEffect(() => {
        ReactGA.event({
            category: "Product",
            action: "View Product",
            label: product?.title,
        });
    }, [product]);

    const { mutateAsync: addToCart, isPending: cartPending } = useAddToCart();
    const { mutateAsync: addToWishList, isPending: wishListPending } = useAddToWishList();
    const { mutateAsync: removeFromWishList, isPending: removeFromWishListPending } = useRemoveFromWishList();
    const { data: wishListData } = useGetWishList();
    const { data: productReviews } = useGetProductAllReview(product?._id);
    const isPending = cartPending || wishListPending || removeFromWishListPending;

    const [count, setCount] = useState<number>(1);
    const [selectedSize, setSelectedSize] = useState<string>();
    const [selectedColor, setSelectedColor] = useState<string>();
    const [selected, setSelected] = useState<number>(0);
    const [added, setAdded] = useState<boolean>(false);
    const [showSizeChart, setShowSizeChart] = useState<boolean>(false);

    const inStock = product?.variants?.reduce((acc: number, variant: any) => acc + variant.stock, 0) > 0;
    const isWishlisted = wishListData?.data?.wishlist?.some((item: any) => item.productId === product?._id);

    const handleAddToCart = async () => {
        try {

            ReactGA.event({
                category: "Cart",
                action: "Add To Cart",
                label: product?.title,
            });

            const data = await addToCart({ productId: product?._id, quantity: count, size: selectedSize, color: selectedColor })

            if (data) {
                setAdded(true);
                setTimeout(() => setAdded(false), 2000);
            }

        } catch (error) {
            console.error("Error adding to cart:", error);
        }
    };

    const totalStock = product?.variants?.reduce((acc: number, variant: any) => acc + variant.stock, 0);
    const totalRating = productReviews?.reduce((acc, review) => acc + review.rating, 0);
    const averageRating = totalRating / productReviews?.length;

    const StarRating = ({ rating = 0 }) => {
        return (
            <div className="flex gap-1 text-yellow-400 text-sm">
                {[1, 2, 3, 4, 5].map((star) => {
                    if (rating >= star) {
                        return <FaStar key={star} />;
                    }
                    if (rating >= star - 0.5) {
                        return <FaStarHalfAlt key={star} />;
                    }
                    return <FaRegStar key={star} />;
                })}
            </div>
        );
    };


    return (
