                            placeholder="Type your question..."
                            className="w-full sm:flex-1 border-gray-400 focus:ring focus:ring-gray-400 border rounded-lg px-3 py-2 sm:px-4 sm:py-3 text-xs sm:text-base outline-none min-w-0"
