import { useState, useEffect } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { toast } from "sonner";
import { LeftBar } from './Leftbar';
import './CSS/Components.css';
import '../index.css';
import { register, verifyOtp, resendOtp } from '../Hooks/Auth'
import { useDispatch, useSelector } from 'react-redux';
import type { RootState } from '../Redux/store';
import { setUser } from '../Redux/authSlice';
import { GoogleLogin } from "@react-oauth/google";
import { useGoogleLogin } from '../Hooks/user';
import { getCart } from '../Api/cartApi';
import { setCart } from '../Redux/cartSlice';

export const SignUp = () => {

    const dispatch = useDispatch();
    const { token } = useSelector((state: RootState) => state.auth);
    const navigate = useNavigate();

    const { mutateAsync: registerUser, isPending } = register();
    const { mutateAsync: verifyOtpUser, isPending: isOtpPending } = verifyOtp();
    const { mutateAsync: resendOtpUser, isPending: isResendPending } = resendOtp();
    const { mutateAsync: googleLoginUser } = useGoogleLogin();

    const [showPassword, setShowPassword] = useState<boolean>(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState<boolean>(false);
    const [otpOpen, setOtpOpen] = useState<boolean>(false);
    const [registeredEmail, setRegisteredEmail] = useState<string>("");

    const [formData, setFormData] = useState({
        name: "",
        email: "",
        mobileNumber: "",
        password: "",
        confirmPassword: ""
    })

    useEffect(() => {
        if (token) {
            toast.success("User already logged in", {
                duration: 1500,
            });
            setTimeout(() => {
                navigate("/");
            }, 1500);
        }
    }, [navigate]);

    const HandleInput = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setFormData((prev) => ({
            ...prev,
            [name]: value,
        }));
    };

    const showPasswordHandler = () => {
        setShowPassword(!showPassword);
    }

    const showConfirmPasswordHandler = () => {
        setShowConfirmPassword(!showConfirmPassword);
    }

    const HandleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();

        if (!formData.name) {
            toast.error("Please fill Name , Is required", {
                duration: 1500,
            });
            return;
        }

        if (!formData.mobileNumber) {
            toast.error("Please fill Mobile No , Is required", {
                duration: 1500,
            });
            return;
        }

        if (!/^[6-9]\d{9}$/.test(formData.mobileNumber)) {
            toast.error("Please enter a valid mobile number", {
                duration: 1500,
            });
            return;
        }

        if (!formData.email) {
            toast.error("Please fill Email , Is required", {
                duration: 1500,
            });
            return;
        }

        if (!formData.password) {
            toast.error("Please fill Password , Is required", {
                duration: 1500,
            });
            return;
        }

        if (!formData.confirmPassword) {
            toast.error("Please fill Confirm Password , Is required", {
                duration: 1500,
            });
            return;
        }

        if (!/\S+@\S+\.\S+/.test(formData.email)) {
            toast.error("Please enter a valid email", {
                duration: 1500,
            });
            return;
        }

        if (formData.password.length < 6) {
            toast.error("Password must be at least 6 characters", {
                duration: 1500,
            });
            return;
        }

        if (!/\d/.test(formData.password)) {
            toast.error("Password must contain at least one number", {
                duration: 1500,
            });
            return;
        }

        if (!/[@$!%*?&]/.test(formData.password)) {
            toast.error("Password must contain at least one special character", {
                duration: 1500,
            });
            return;
        }

        if (!/[A-Z]/.test(formData.password)) {
            toast.error("Password must contain at least one uppercase letter", {
                duration: 1500,
            });
            return;
        }

        if (formData.password !== formData.confirmPassword) {
            toast.error("Passwords do not match", {
                duration: 1500,
            });
            return;
        }
        try {
            const userData = await registerUser(formData);

            if (!userData?.success) {
                toast.error("User not created", {
                    duration: 1500,
                });
                return;
            }

            toast.success("User created successfully", {
                duration: 1500,
            });

            setRegisteredEmail(formData.email);

            setFormData({
                name: "",
                email: "",
                password: "",
                mobileNumber: "",
                confirmPassword: ""
            });

            dispatch(
                setUser({
                    token: userData.data.token,
                    user: {
                        name: userData.data.user.name,
                        email: userData.data.user.email,
                    },
                    activeNav: ''
                })
            )

            setTimeout(() => {
                setOtpOpen(true);
            }, 1500);

        } catch (error) {
            const err = error as { response?: { data?: { message?: string } } };
            const msg = err.response?.data?.message || "Something went wrong";
            toast.error(msg, {
                duration: 1500,
            });
        }

    }

    const [otp, setOtp] = useState({
        otp1: "",
        otp2: "",
        otp3: "",
        otp4: "",
        otp5: "",
        otp6: ""
    })

    const handleOTPChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;

        if (value !== "" && !/^[0-9]$/.test(value)) return;

        setOtp((prev) => ({
            ...prev,
            [name]: value,
        }));

        if (value !== "") {
            const nextSibling = e.target.nextElementSibling as HTMLInputElement | null;
            if (nextSibling) {
                nextSibling.focus();
            }
        } else {
            const previousSibling = e.target.previousElementSibling as HTMLInputElement | null;
            if (previousSibling) {
                previousSibling.focus();
            }
        }
    }

    const verifyOTP = async (e: React.MouseEvent<HTMLButtonElement>) => {
        e.preventDefault();

        const otpString = `${otp.otp1}${otp.otp2}${otp.otp3}${otp.otp4}${otp.otp5}${otp.otp6}`;

        if (otpString.length !== 6) {
            toast.error("Please enter a valid 6-digit OTP", {
                duration: 1500,
            });
            return;
        }

        try {
            const response = await verifyOtpUser({
                email: registeredEmail,
                otp: otpString
            });

            if (!response?.success) {
                toast.error(response?.message || "OTP verification failed", {
                    duration: 1500,
                });
                return;
            }

            toast.success(response.message || "OTP Verified Successfully!", {
                duration: 1500,
            });

            setTimeout(() => {
                setOtpOpen(false);
                navigate("/");
            }, 1500);

        } catch (error) {
            const err = error as { response?: { data?: { message?: string } } };
            const msg = err.response?.data?.message || "OTP verification failed";
            toast.error(msg, {
                duration: 1500,
            });
        }
    }

    const handleResendOTP = async () => {
        if (!registeredEmail) {
            toast.error("No registered email found", { duration: 1500 });
            return;
        }

        try {
            const response = await resendOtpUser({ email: registeredEmail });

            if (!response?.success) {
                toast.error(response?.message || "Failed to resend OTP", {
                    duration: 1500,
                });
                return;
            }

            toast.success(response.message || "OTP resent successfully!", {
                duration: 1500,
            });
        } catch (error) {
            const err = error as { response?: { data?: { message?: string } } };
            const msg = err.response?.data?.message || "Failed to resend OTP";
            toast.error(msg, {
                duration: 1500,
            });
        }
    }

    const handleGoogleLogin = async (response: any) => {
        try {
            const res = await googleLoginUser(response.credential);
            if (res.success) {

                dispatch(
                    setUser({
                        token: res.data.token,
                        user: {
                            name: res.data.user.name,
                            email: res.data.user.email
                        },
                        activeNav: ''
                    })
                )

                try {
                    const fetchedCart = await getCart();

                    if (fetchedCart && fetchedCart.length > 0) {
                        dispatch(setCart(fetchedCart));
                    }
                } catch (cartError) {
                    console.error("Failed to fetch cart after login:", cartError);
                }

                setTimeout(() => {
                    navigate("/");
                }, 1500);
            }
        } catch (error) {
            const err = error as { response?: { data?: { message?: string } } };
            const msg = err.response?.data?.message || "Login failed. Please try again.";
            toast.error(msg, {
                duration: 1500,
            });
        }
    }

    return (
        <div className="min-h-screen bg-white flex">

            <LeftBar />

            <div className="relative w-full lg:w-1/2 flex items-center justify-center p-4 sm:p-8 lg:p-12">

                {otpOpen && (
                    <>
